#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<long long>a(n);for(auto&x:a)scanf("%lld",&x);sort(a.begin(),a.end());int l=0,r=n-1;long long best=LLONG_MAX,pa=a[0],pb=a[1];while(l<r){long long s=a[l]+a[r];if(llabs(s)<best){best=llabs(s);pa=a[l];pb=a[r];}if(s<0)l++;else r--;}printf("%lld %lld\n",pa,pb);}
